import React, { useRef, useState, useEffect, useCallback } from 'react';
import { useImageCurves } from '../../hooks/useImageCurves';
import { Activity, Download, RefreshCw, Trash2, RotateCcw, Image as ImageIcon, Plus } from 'lucide-react';
import Dropzone from '../Dropzone';
import { applyCurvesToImage, formatBytes } from '../../utils/imageHelper';
import { CurvePoint } from '../../types';

interface CurvesAdjustmentViewProps {
  controller: ReturnType<typeof useImageCurves>;
}

const CurvesAdjustmentView: React.FC<CurvesAdjustmentViewProps> = ({ controller }) => {
  const {
    files,
    points,
    isProcessing,
    activePreviewId,
    setActivePreviewId,
    handleFilesAdded,
    handleRemoveFile,
    addPoint,
    updatePoint,
    removePoint,
    resetCurves,
    applyBatch,
    downloadZip,
    lut
  } = controller;

  const graphRef = useRef<HTMLDivElement>(null);
  const [draggingPointId, setDraggingPointId] = useState<string | null>(null);
  const [previewBlobUrl, setPreviewBlobUrl] = useState<string | null>(null);
  const [isDragOver, setIsDragOver] = useState(false);

  // Generate low-res preview when active image or LUT changes
  useEffect(() => {
    const activeFile = files.find(f => f.id === activePreviewId);
    if (!activeFile) {
        setPreviewBlobUrl(null);
        return;
    }

    const timer = setTimeout(async () => {
        try {
            const blob = await applyCurvesToImage(activeFile.file, lut);
            const url = URL.createObjectURL(blob);
            setPreviewBlobUrl(prev => {
                if (prev) URL.revokeObjectURL(prev);
                return url;
            });
        } catch (e) {
            console.error("Preview error", e);
        }
    }, 50);

    return () => clearTimeout(timer);
  }, [activePreviewId, lut, files.length]); 

  const handleGraphClick = (e: React.MouseEvent) => {
    if (draggingPointId) return;
    if (!graphRef.current) return;

    const rect = graphRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));

    addPoint(x, y);
  };

  const handleMouseMove = (e: MouseEvent) => {
    if (!draggingPointId || !graphRef.current) return;
    e.preventDefault();
    const rect = graphRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));

    updatePoint(draggingPointId, x, y);
  };

  const handleMouseUp = () => {
    setDraggingPointId(null);
  };

  useEffect(() => {
    if (draggingPointId) {
        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [draggingPointId]);

  const generateSvgPath = () => {
     let d = `M 0 ${255 - lut[0]}`;
     for(let i = 1; i < 256; i++) {
         const xPercent = (i / 255) * 100;
         const yPercent = 100 - (lut[i] / 255) * 100;
         d += ` L ${xPercent.toFixed(2)}% ${yPercent.toFixed(2)}%`;
     }
     return d;
  };

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(true);
  };
  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);
  };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);

    const droppedFiles = Array.from(e.dataTransfer.files).filter(
        (f: File) => f.type === 'image/png' || f.type === 'image/jpeg'
    );
    if (droppedFiles.length > 0) {
        handleFilesAdded(droppedFiles);
    }
  };

  const completedCount = files.filter(f => f.status === 'COMPLETED').length;
  const activeFileItem = files.find(f => f.id === activePreviewId);

  return (
    <main className="grid grid-cols-1 lg:grid-cols-12 gap-8 flex-1 relative z-10 animate-in fade-in slide-in-from-bottom-2 duration-300">

      {/* Left Column: Image Preview Area + Strip */}
      <div className="lg:col-span-8 flex flex-col gap-4 order-2 lg:order-1 h-auto min-h-0">
        {files.length === 0 ? (
          <div className="flex-1 flex flex-col h-full">
             <Dropzone onFilesAdded={handleFilesAdded} />
             <div className="flex-1 mt-6 flex flex-col items-center justify-center text-cyber-dim/40 border-2 border-dashed border-cyber-border/30 rounded-xl bg-cyber-black/20 p-8 min-h-[400px]">
               <Activity size={80} strokeWidth={0.5} className="text-cyber-border" />
               <p className="mt-6 font-mono text-sm tracking-[0.3em] uppercase">No Images Loaded</p>
            </div>
          </div>
        ) : (
          <div 
            className={`flex-1 flex flex-col bg-cyber-dark/80 border rounded-xl overflow-hidden shadow-inner transition-colors relative ${isDragOver ? 'border-cyber-primary bg-cyber-primary/5' : 'border-cyber-border'}`}
            onDragOver={(e) => { e.preventDefault(); setIsDragOver(true); }}
            onDragEnter={handleDragEnter}
            onDragLeave={handleDragLeave}
            onDrop={handleDrop}
          >
             {isDragOver && (
                <div className="absolute inset-0 z-50 flex items-center justify-center bg-cyber-black/80 backdrop-blur-sm border-2 border-cyber-primary border-dashed rounded-xl pointer-events-none">
                    <div className="text-cyber-primary font-bold text-xl flex items-center gap-3 animate-pulse">
                        <Plus size={32} />
                        ADD MORE IMAGES
                    </div>
                </div>
             )}

            {/* Main Preview Area */}
            <div className="flex-1 relative overflow-hidden flex items-center justify-center bg-[radial-gradient(#334155_1px,transparent_1px)] bg-[size:20px_20px] min-h-[300px] lg:min-h-[400px]">
                <div className="absolute inset-0 opacity-20 pointer-events-none"></div>

                {activeFileItem ? (
                    <div className="relative w-full h-full p-4 flex flex-col items-center justify-center">
                        <div className="relative shadow-2xl border border-cyber-border/50 max-h-full max-w-full">
                            <img 
                                src={previewBlobUrl || activeFileItem.previewUrl} 
                                className="max-w-full block"
                                style={{ maxHeight: 'min(60vh, 700px)', objectFit: 'contain' }}
                                alt="Preview" 
                            />
                            <div className="absolute top-2 right-2 bg-cyber-black/80 text-cyber-primary text-[10px] font-mono px-2 py-1 rounded border border-cyber-primary/30 backdrop-blur-sm pointer-events-none shadow-lg">
                                PREVIEW
                            </div>
                        </div>

                        <div className="mt-4 bg-cyber-panel/80 backdrop-blur-md border border-cyber-border/50 px-4 py-1.5 rounded-full flex items-center gap-4 text-xs font-mono shadow-lg">
                             <div className="flex items-center gap-2 text-cyber-text max-w-[150px] sm:max-w-[250px]">
                                <ImageIcon size={12} className="text-cyber-dim" />
                                <span className="truncate" title={activeFileItem.file.name}>{activeFileItem.file.name}</span>
                             </div>
                             <div className="w-px h-3 bg-cyber-dim/30"></div>
                             <div className="text-cyber-dim">
                                {activeFileItem.width} <span className="text-cyber-dim/50">x</span> {activeFileItem.height}
                             </div>
                        </div>
                    </div>
                ) : (
                    <div className="text-cyber-dim font-mono text-sm">Select an image to preview</div>
                )}
            </div>

            {/* File Strip */}
            <div className="h-24 bg-cyber-black/90 border-t border-cyber-border/50 p-2 flex gap-3 overflow-x-auto custom-scrollbar backdrop-blur-md flex-shrink-0 z-10 items-center">
                {files.map(file => (
                    <div 
                        key={file.id} 
                        onClick={() => setActivePreviewId(file.id)}
                        className={`
                            relative w-16 h-16 flex-shrink-0 cursor-pointer border rounded-md overflow-hidden transition-all group/item
                            ${activePreviewId === file.id ? 'border-cyber-primary ring-1 ring-cyber-primary shadow-[0_0_10px_rgba(6,182,212,0.3)] opacity-100' : 'border-cyber-border opacity-50 hover:opacity-90'}
                        `}
                    >
                        <img src={file.previewUrl} className="w-full h-full object-cover" alt="" />
                        {file.status === 'COMPLETED' && <div className="absolute inset-0 bg-emerald-500/20 flex items-center justify-center"><div className="w-2 h-2 rounded-full bg-emerald-400 shadow-neon"></div></div>}
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleRemoveFile(file.id); }}
                            className="absolute top-1 right-1 bg-black/70 text-white p-1 rounded-sm opacity-0 group-hover/item:opacity-100 hover:bg-red-500 hover:text-white transition-all backdrop-blur-sm"
                        >
                            <Trash2 size={10} />
                        </button>
                    </div>
                ))}

                {/* Compact Dropzone in strip - Fixed alignment and size */}
                <div className="w-16 h-16 flex-shrink-0">
                     <Dropzone onFilesAdded={handleFilesAdded} compact={true} />
                </div>
            </div>
          </div>
        )}
      </div>

      {/* Right Column: Curve Editor */}
      <div className="lg:col-span-4 space-y-6 order-1 lg:order-2 flex flex-col h-fit sticky top-8">
        <div className="bg-cyber-panel/40 backdrop-blur-md border border-cyber-border p-6 shadow-2xl rounded-lg relative overflow-hidden">
            <div className="absolute top-0 right-0 w-20 h-20 bg-cyber-primary/5 rounded-full blur-2xl -mr-10 -mt-10 pointer-events-none"></div>

            <div className="flex items-center justify-between mb-6 relative z-10">
