                    ></div>
                ))}
            </div>

            <div className="mt-4 text-center">
                <p className="text-[10px] text-cyber-dim uppercase tracking-widest font-mono">
                    Double-click point to delete • Drag to adjust
                </p>
            </div>
        </div>

        <div className="bg-cyber-panel/20 border border-cyber-border p-4 rounded-lg space-y-3">
             <div className="flex justify-between text-xs font-mono text-cyber-dim uppercase">
                 <span>Batch Ready</span>
                 <span className={files.length > 0 ? 'text-cyber-text' : ''}>{files.length} Images</span>
             </div>

             <button
                onClick={applyBatch}
                disabled={isProcessing || files.length === 0}
                className="w-full py-3 bg-cyber-primary/10 border border-cyber-primary text-cyber-primary font-bold text-xs uppercase tracking-widest hover:bg-cyber-primary/20 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
             >
                {isProcessing ? <RefreshCw size={16} className="animate-spin" /> : <RefreshCw size={16} />}
                APPLY CURVES
             </button>

             {completedCount > 0 && !isProcessing && (
                <button
                    onClick={downloadZip}
                    className="w-full py-3 bg-cyber-accent/10 border border-cyber-accent text-cyber-accent font-bold text-xs uppercase tracking-widest hover:bg-cyber-accent/20 transition-all flex items-center justify-center gap-2"
                >
                    <Download size={16} />
                    DOWNLOAD ZIP ({completedCount})
                </button>
             )}
        </div>
      </div>

    </main>
  );
};

export default CurvesAdjustmentView;

import { useState, useCallback, useMemo, useEffect } from 'react';
import { ImageFile, ConversionStatus, CurvePoint } from '../types';
import { applyCurvesToImage, getImageDimensions } from '../utils/imageHelper';
import { generateCurveLUT } from '../utils/curveAlgorithms';
import { generateId, getZip } from '../utils/common';

const DEFAULT_POINTS: CurvePoint[] = [
  { id: 'start', x: 0, y: 0 },
  { id: 'end', x: 255, y: 255 }
];

export interface ReferenceImage {
  id: string;
  file: File;
  previewUrl: string;
}

export const useImageCurves = () => {
  const [files, setFiles] = useState<ImageFile[]>([]);
  const [points, setPoints] = useState<CurvePoint[]>(DEFAULT_POINTS);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activePreviewId, setActivePreviewId] = useState<string | null>(null);

  // AB Comparison State
  const [referenceImage, setReferenceImage] = useState<ReferenceImage | null>(null);
  const [isABMode, setIsABMode] = useState(false);
  const [splitPosition, setSplitPosition] = useState(50); // 0 to 100

  // Computed LUT based on points
  const lut = useMemo(() => generateCurveLUT(points), [points]);

  const handleFilesAdded = useCallback(async (newFiles: File[]) => {
    const processedFilesPromises = newFiles.map(async (file) => {
      const dimensions = await getImageDimensions(file);
      return {
        id: generateId(),
        file,
        previewUrl: URL.createObjectURL(file), 
        status: ConversionStatus.IDLE,
        originalSize: file.size,
        width: dimensions.width,
        height: dimensions.height,
      } as ImageFile;
    });

    const newImageFiles = await Promise.all(processedFilesPromises);
    setFiles(prev => {
        const updated = [...prev, ...newImageFiles];
        if (!activePreviewId && updated.length > 0) {
            setActivePreviewId(updated[0].id);
        }
        return updated;
    });
  }, [activePreviewId]);

  const handleReferenceAdded = useCallback(async (file: File) => {
    if (referenceImage) {
      URL.revokeObjectURL(referenceImage.previewUrl);
    }
    const previewUrl = URL.createObjectURL(file);
    setReferenceImage({
      id: generateId(),
      file,
      previewUrl
    });
    setIsABMode(true);
  }, [referenceImage]);

  const clearReference = useCallback(() => {
    if (referenceImage) {
      URL.revokeObjectURL(referenceImage.previewUrl);
    }
    setReferenceImage(null);
  }, [referenceImage]);

  const handleRemoveFile = useCallback((id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) {
        URL.revokeObjectURL(target.previewUrl);
      }
      const remaining = prev.filter(f => f.id !== id);
      if (activePreviewId === id) {
          setActivePreviewId(remaining.length > 0 ? remaining[0].id : null);
      }
      return remaining;
    });
  }, [activePreviewId]);

  const addPoint = (x: number, y: number) => {
    if (points.some(p => Math.abs(p.x - x) < 5)) return;
    const newPoint: CurvePoint = { id: generateId(), x, y };
    setPoints(prev => [...prev, newPoint].sort((a, b) => a.x - b.x));
  };

  const updatePoint = (id: string, x: number, y: number) => {
    setPoints(prev => prev.map(p => {
        if (p.id !== id) return p;
        return { ...p, x: Math.max(0, Math.min(255, x)), y: Math.max(0, Math.min(255, y)) };
    }).sort((a, b) => a.x - b.x));
  };

  const removePoint = (id: string) => {
      if (points.length <= 2) return; 
      setPoints(prev => prev.filter(p => p.id !== id));
  };

  const resetCurves = () => setPoints([
      { id: 'start', x: 0, y: 0 },
      { id: 'end', x: 255, y: 255 }
  ]);

  const applyBatch = async () => {
    setIsProcessing(true);
    for (const file of files) {
        if (file.status === ConversionStatus.COMPLETED) continue;
        setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: ConversionStatus.PROCESSING } : f));
        try {
            const blob = await applyCurvesToImage(file.file, lut);
            setFiles(prev => prev.map(f => 
                f.id === file.id ? { 
                    ...f, 
                    status: ConversionStatus.COMPLETED, 
                    convertedBlob: blob,
                    convertedSize: blob.size 
                } : f
            ));
        } catch (e) {
            console.error(e);
            setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: ConversionStatus.ERROR } : f));
        }
    }
    setIsProcessing(false);
  };

  const downloadZip = async () => {
      try {
        const zip = getZip();
        const completedFiles = files.filter(f => f.status === ConversionStatus.COMPLETED && f.convertedBlob);
        if (completedFiles.length === 0) return;
        completedFiles.forEach(f => {
          const fileName = f.file.name.replace(/\.(png|jpe?g)$/i, '') + '_curve.jpg';
          if (f.convertedBlob) {
            zip.file(fileName, f.convertedBlob);
          }
        });
        const content = await zip.generateAsync({ type: "blob" });
        const url = URL.createObjectURL(content);
        const a = document.createElement("a");
        a.href = url;
        a.download = `BatchBox_Curves_${new Date().toISOString().slice(0,10)}.zip`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      } catch (error) {
        console.error("ZIP generation failed", error);
        alert("Failed to generate ZIP.");
      }
  };

  return {
      files,
      points,
      isProcessing,
      activePreviewId,
      setActivePreviewId,
      handleFilesAdded,
      handleRemoveFile,
      addPoint,
      updatePoint,
      removePoint,
      resetCurves,
      applyBatch,
      downloadZip,
      lut,
      // AB Mode exports
      referenceImage,
      handleReferenceAdded,
      clearReference,
      isABMode,
      setIsABMode,
      splitPosition,
      setSplitPosition
  };
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { useImageCurves } from '../../hooks/useImageCurves';
import { Activity, Download, RefreshCw, Trash2, RotateCcw, Image as ImageIcon, Plus, Columns, EyeOff, Eye, XCircle, Split } from 'lucide-react';
import Dropzone from '../Dropzone';
import { applyCurvesToImage, formatBytes } from '../../utils/imageHelper';
import { CurvePoint } from '../../types';

interface CurvesAdjustmentViewProps {
  controller: ReturnType<typeof useImageCurves>;
}

const CurvesAdjustmentView: React.FC<CurvesAdjustmentViewProps> = ({ controller }) => {
  const {
    files,
    points,
    isProcessing,
    activePreviewId,
    setActivePreviewId,
    handleFilesAdded,
    handleRemoveFile,
    addPoint,
    updatePoint,
    removePoint,
    resetCurves,
    applyBatch,
    downloadZip,
    lut,
    // AB Mode
    referenceImage,
    handleReferenceAdded,
    clearReference,
    isABMode,
    setIsABMode,
    splitPosition,
    setSplitPosition
  } = controller;

  const graphRef = useRef<HTMLDivElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const [draggingPointId, setDraggingPointId] = useState<string | null>(null);
  const [previewBlobUrl, setPreviewBlobUrl] = useState<string | null>(null);
  const [isDragOver, setIsDragOver] = useState(false);
  const [isResizingSplit, setIsResizingSplit] = useState(false);

  // Generate low-res preview when active image or LUT changes
  useEffect(() => {
    const activeFile = files.find(f => f.id === activePreviewId);
    if (!activeFile) {
        setPreviewBlobUrl(null);
        return;
    }

    const timer = setTimeout(async () => {
        try {
            const blob = await applyCurvesToImage(activeFile.file, lut);
            const url = URL.createObjectURL(blob);
            setPreviewBlobUrl(prev => {
                if (prev) URL.revokeObjectURL(prev);
                return url;
            });
        } catch (e) {
            console.error("Preview error", e);
        }
    }, 50);

    return () => clearTimeout(timer);
  }, [activePreviewId, lut, files.length]); 

  const handleGraphClick = (e: React.MouseEvent) => {
    if (draggingPointId) return;
    if (!graphRef.current) return;
    const rect = graphRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));
    addPoint(x, y);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (draggingPointId && graphRef.current) {
      const rect = graphRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));
      updatePoint(draggingPointId, x, y);
    }

    if (isResizingSplit && previewContainerRef.current) {
      const rect = previewContainerRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(100, ((e.clientX - rect.left) / rect.width) * 100));
      setSplitPosition(x);
    }
  }, [draggingPointId, isResizingSplit, updatePoint, setSplitPosition]);

  const handleMouseUp = useCallback(() => {
    setDraggingPointId(null);
    setIsResizingSplit(false);
  }, []);

  useEffect(() => {
    if (draggingPointId || isResizingSplit) {
        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [draggingPointId, isResizingSplit, handleMouseMove, handleMouseUp]);

  const generateSvgPath = () => {
     let d = `M 0 ${255 - lut[0]}`;
     for(let i = 1; i < 256; i++) {
         const xPercent = (i / 255) * 100;
         const yPercent = 100 - (lut[i] / 255) * 100;
         d += ` L ${xPercent.toFixed(2)}% ${yPercent.toFixed(2)}%`;
     }
     return d;
  };

  const handleReferenceInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleReferenceAdded(file);
    e.target.value = '';
  };

  const activeFileItem = files.find(f => f.id === activePreviewId);

  return (
    <main className="grid grid-cols-1 lg:grid-cols-12 gap-8 flex-1 relative z-10 animate-in fade-in slide-in-from-bottom-2 duration-300">

      {/* Left Column: Image Preview Area + Strip */}
