               <Activity size={80} strokeWidth={0.5} className="text-cyber-border" />
               <p className="mt-6 font-mono text-sm tracking-[0.3em] uppercase">No Images Loaded</p>
            </div>
          </div>
        ) : (
          <div className="flex-1 flex flex-col bg-cyber-dark/80 border border-cyber-border rounded-xl overflow-hidden shadow-inner relative">
            {/* Header / Toolbar for Preview */}
