                <div className="h-4 w-px bg-cyber-border/50"></div>

                <div className="flex items-center gap-2">
                  <label className="cursor-pointer bg-cyber-panel/50 border border-cyber-border px-3 py-1.5 rounded text-xs font-mono text-cyber-dim hover:text-cyber-text transition-all flex items-center gap-2 hover:border-cyber-primary/50">
                    <ImageIcon size={14} />
                    {referenceImage ? 'Change Ref' : 'Upload Ref'}
                    <input type="file" className="hidden" accept="image/*" onChange={handleReferenceInputChange} />
                  </label>

                  {referenceImage && (
                    <button 
                      onClick={clearReference}
                      className="text-red-400 hover:text-red-300 p-1.5"
                      title="Clear Reference"
                    >
                      <XCircle size={14} />
                    </button>
                  )}
                </div>
              </div>

              <div className="text-[10px] font-mono text-cyber-dim uppercase hidden sm:block">
                {isABMode ? (referenceImage ? 'A: Reference | B: Adjusted' : 'A: Original | B: Adjusted') : 'Visualizing Results'}
              </div>
            </div>

            {/* Main Preview Area */}
            <div 
              ref={previewContainerRef}
              className="flex-1 relative overflow-hidden flex items-center justify-center bg-[radial-gradient(#334155_1px,transparent_1px)] bg-[size:20px_20px] min-h-[300px] lg:min-h-[400px]"
            >
                {activeFileItem ? (
                    <div className="relative w-full h-full p-4 flex flex-col items-center justify-center">
                        <div className="relative shadow-2xl border border-cyber-border/50 max-h-full max-w-full group/preview overflow-hidden">

                            {/* Comparison Side B (Adjusted) - Always background or clipped */}
                            <img 
                                src={previewBlobUrl || activeFileItem.previewUrl} 
                                className="max-w-full block select-none pointer-events-none"
                                style={{ maxHeight: 'min(60vh, 700px)', objectFit: 'contain' }}
                                alt="Adjusted Preview" 
                            />

                            {/* Comparison Side A (Original or Reference) */}
                            {isABMode && (
                              <>
                                <div 
                                  className="absolute top-0 left-0 h-full overflow-hidden border-r border-cyber-primary/50 z-10"
                                  style={{ width: `${splitPosition}%` }}
                                >
                                  <img 
                                      src={referenceImage?.previewUrl || activeFileItem.previewUrl} 
                                      className="max-w-none block select-none pointer-events-none"
                                      style={{ 
                                        height: '100%', 
                                        width: 'auto',
                                        // This ensures the image doesn't stretch and stays aligned with the bottom image
                                        // We use the same container relative sizing
                                        position: 'absolute',
                                        top: 0,
                                        left: 0,
                                        minHeight: '100%',
                                        minWidth: '100%',
                                        objectFit: 'contain',
                                        objectPosition: 'center'
                                      }}
                                      alt="Comparison Preview" 
                                  />
                                </div>

                                {/* Draggable Divider Handle */}
                                <div 
                                  className="absolute top-0 bottom-0 z-20 w-1 bg-cyber-primary shadow-neon cursor-col-resize flex items-center justify-center"
                                  style={{ left: `calc(${splitPosition}% - 0.5px)` }}
                                  onMouseDown={(e) => { e.preventDefault(); setIsResizingSplit(true); }}
                                >
                                   <div className="w-6 h-6 bg-cyber-primary text-cyber-black rounded-full flex items-center justify-center shadow-lg border-2 border-white/20">
                                      <Split size={12} className="rotate-90" />
                                   </div>
                                </div>

                                <div className="absolute top-2 left-2 z-30 bg-cyber-black/80 text-cyber-accent text-[9px] font-mono px-2 py-0.5 rounded border border-cyber-accent/30 backdrop-blur-sm pointer-events-none shadow-lg">
                                  SIDE A: {referenceImage ? 'REF' : 'ORIG'}
                                </div>
                                <div className="absolute top-2 right-2 z-30 bg-cyber-black/80 text-cyber-primary text-[9px] font-mono px-2 py-0.5 rounded border border-cyber-primary/30 backdrop-blur-sm pointer-events-none shadow-lg">
                                  SIDE B: ADJUSTED
                                </div>
                              </>
                            )}

                            {!isABMode && (
                              <div className="absolute top-2 right-2 bg-cyber-black/80 text-cyber-primary text-[10px] font-mono px-2 py-1 rounded border border-cyber-primary/30 backdrop-blur-sm pointer-events-none shadow-lg">
                                PREVIEW
                              </div>
                            )}
                        </div>

                        <div className="mt-4 bg-cyber-panel/80 backdrop-blur-md border border-cyber-border/50 px-4 py-1.5 rounded-full flex items-center gap-4 text-xs font-mono shadow-lg">
