                        `}
                    >
                        <img src={file.previewUrl} className="w-full h-full object-cover" alt="" />
                        {file.status === 'COMPLETED' && <div className="absolute inset-0 bg-emerald-500/20 flex items-center justify-center"><div className="w-2 h-2 rounded-full bg-emerald-400 shadow-neon"></div></div>}
                        <button 
