                <button 
                    onClick={resetCurves}
                    className="text-[10px] flex items-center gap-1 text-cyber-dim hover:text-cyber-primary transition-colors uppercase tracking-wider bg-cyber-black/50 px-2 py-1 rounded border border-cyber-border/50"
                >
                    <RotateCcw size={10} /> Reset
                </button>
            </div>

            <div className="aspect-square relative bg-cyber-black border border-cyber-border rounded-lg shadow-inner select-none cursor-crosshair group overflow-hidden" ref={graphRef} onClick={handleGraphClick}>
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-20">
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div></div>
                </div>

                <div className="absolute inset-0 border-t border-l border-transparent">
                     <svg className="w-full h-full pointer-events-none opacity-10" viewBox="0 0 100 100" preserveAspectRatio="none">
                         <line x1="0" y1="100" x2="100" y2="0" stroke="currentColor" strokeWidth="0.5" className="text-cyber-dim" />
                     </svg>
                </div>

                <svg className="absolute inset-0 w-full h-full pointer-events-none z-10 overflow-visible">
                    <path 
                        d={generateSvgPath()} 
                        fill="none" 
                        stroke="#06b6d4" 
                        strokeWidth="4" 
                        strokeOpacity="0.2"
                        vectorEffect="non-scaling-stroke"
                        className="blur-sm"
                    />
                    <path 
                        d={generateSvgPath()} 
                        fill="none" 
                        stroke="#06b6d4" 
                        strokeWidth="2" 
                        vectorEffect="non-scaling-stroke"
                        className="drop-shadow-[0_0_2px_rgba(255,255,255,0.5)]"
                    />
                    <path 
                        d={`${generateSvgPath()} L 100% 100% L 0 100% Z`} 
                        fill="url(#curveGradient)" 
                        opacity="0.15"
                    />
                    <defs>
                        <linearGradient id="curveGradient" x1="0" x2="0" y1="0" y2="1">
                            <stop offset="0%" stopColor="#06b6d4" />
                            <stop offset="100%" stopColor="transparent" />
                        </linearGradient>
                    </defs>
                </svg>

                {points.map((p, index) => (
                    <div
                        key={p.id}
                        className={`absolute w-3 h-3 -ml-1.5 -mt-1.5 rounded-full border-2 cursor-grab active:cursor-grabbing transition-transform z-20 ${
                            draggingPointId === p.id 
                            ? 'bg-cyber-text border-cyber-primary shadow-[0_0_15px_rgba(6,182,212,0.8)] scale-150' 
                            : 'bg-cyber-black border-cyber-primary hover:scale-125'
                        }`}
                        style={{
                            left: `${(p.x / 255) * 100}%`,
                            top: `${100 - (p.y / 255) * 100}%`
                        }}
                        onMouseDown={(e) => {
                            e.stopPropagation();
                            setDraggingPointId(p.id);
                        }}
                        onDoubleClick={(e) => {
                            e.stopPropagation();
                            if (index !== 0 && index !== points.length - 1) {
                                removePoint(p.id);
                            }
                        }}
                    ></div>
                ))}
            </div>

            <div className="mt-4 text-center">
                <p className="text-[10px] text-cyber-dim uppercase tracking-widest font-mono">
                    Double-click point to delete • Drag to adjust
                </p>
            </div>
        </div>

        <div className="bg-cyber-panel/20 border border-cyber-border p-4 rounded-lg space-y-3">
             <div className="flex justify-between text-xs font-mono text-cyber-dim uppercase">
                 <span>Batch Ready</span>
                 <span className={files.length > 0 ? 'text-cyber-text' : ''}>{files.length} Images</span>
             </div>

             <button
                onClick={applyBatch}
                disabled={isProcessing || files.length === 0}
                className="w-full py-3 bg-cyber-primary/10 border border-cyber-primary text-cyber-primary font-bold text-xs uppercase tracking-widest hover:bg-cyber-primary/20 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
             >
                {isProcessing ? <RefreshCw size={16} className="animate-spin" /> : <RefreshCw size={16} />}
                APPLY CURVES
             </button>

             {completedCount > 0 && !isProcessing && (
                <button
                    onClick={downloadZip}
                    className="w-full py-3 bg-cyber-accent/10 border border-cyber-accent text-cyber-accent font-bold text-xs uppercase tracking-widest hover:bg-cyber-accent/20 transition-all flex items-center justify-center gap-2"
                >
                    <Download size={16} />
                    DOWNLOAD ZIP ({completedCount})
                </button>
             )}
        </div>
      </div>
    </main>
  );
};

export default CurvesAdjustmentView;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { useImageCurves } from '../../hooks/useImageCurves';
import { Activity, Download, RefreshCw, Trash2, RotateCcw, Image as ImageIcon, Plus, Columns, EyeOff, Eye, XCircle, Split } from 'lucide-react';
import Dropzone from '../Dropzone';
import { applyCurvesToImage, formatBytes } from '../../utils/imageHelper';
// Fix: Added ConversionStatus to imports from types.ts
import { CurvePoint, ConversionStatus } from '../../types';

interface CurvesAdjustmentViewProps {
  controller: ReturnType<typeof useImageCurves>;
}

const CurvesAdjustmentView: React.FC<CurvesAdjustmentViewProps> = ({ controller }) => {
  const {
    files,
    points,
    isProcessing,
    activePreviewId,
    setActivePreviewId,
    handleFilesAdded,
    handleRemoveFile,
    addPoint,
    updatePoint,
    removePoint,
    resetCurves,
    applyBatch,
    downloadZip,
    lut,
    // AB Mode
    referenceImage,
    handleReferenceAdded,
    clearReference,
    isABMode,
    setIsABMode,
    splitPosition,
    setSplitPosition
  } = controller;

  const graphRef = useRef<HTMLDivElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const [draggingPointId, setDraggingPointId] = useState<string | null>(null);
  const [previewBlobUrl, setPreviewBlobUrl] = useState<string | null>(null);
  const [isDragOver, setIsDragOver] = useState(false);
  const [isResizingSplit, setIsResizingSplit] = useState(false);

  // Fix: Calculate completedCount based on file statuses to resolve "Cannot find name 'completedCount'" error.
  const completedCount = files.filter(f => f.status === ConversionStatus.COMPLETED).length;

  // Generate low-res preview when active image or LUT changes
  useEffect(() => {
    const activeFile = files.find(f => f.id === activePreviewId);
    if (!activeFile) {
        setPreviewBlobUrl(null);
        return;
    }

    const timer = setTimeout(async () => {
        try {
            const blob = await applyCurvesToImage(activeFile.file, lut);
            const url = URL.createObjectURL(blob);
            setPreviewBlobUrl(prev => {
                if (prev) URL.revokeObjectURL(prev);
                return url;
            });
        } catch (e) {
            console.error("Preview error", e);
        }
    }, 50);

    return () => clearTimeout(timer);
  }, [activePreviewId, lut, files.length]); 

  const handleGraphClick = (e: React.MouseEvent) => {
    if (draggingPointId) return;
    if (!graphRef.current) return;
    const rect = graphRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));
    addPoint(x, y);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (draggingPointId && graphRef.current) {
      const rect = graphRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));
      updatePoint(draggingPointId, x, y);
    }

    if (isResizingSplit && previewContainerRef.current) {
      const rect = previewContainerRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(100, ((e.clientX - rect.left) / rect.width) * 100));
      setSplitPosition(x);
    }
  }, [draggingPointId, isResizingSplit, updatePoint, setSplitPosition]);

  const handleMouseUp = useCallback(() => {
    setDraggingPointId(null);
    setIsResizingSplit(false);
  }, []);

  useEffect(() => {
    if (draggingPointId || isResizingSplit) {
        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [draggingPointId, isResizingSplit, handleMouseMove, handleMouseUp]);

  const generateSvgPath = () => {
     let d = `M 0 ${255 - lut[0]}`;
     for(let i = 1; i < 256; i++) {
         const xPercent = (i / 255) * 100;
         const yPercent = 100 - (lut[i] / 255) * 100;
         d += ` L ${xPercent.toFixed(2)}% ${yPercent.toFixed(2)}%`;
     }
     return d;
  };

  const handleReferenceInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleReferenceAdded(file);
    e.target.value = '';
  };

  const activeFileItem = files.find(f => f.id === activePreviewId);

  return (
    <main className="grid grid-cols-1 lg:grid-cols-12 gap-8 flex-1 relative z-10 animate-in fade-in slide-in-from-bottom-2 duration-300">

      {/* Left Column: Image Preview Area + Strip */}
      <div className="lg:col-span-8 flex flex-col gap-4 order-2 lg:order-1 h-auto min-h-0">
        {files.length === 0 ? (
          <div className="flex-1 flex flex-col h-full">
             <Dropzone onFilesAdded={handleFilesAdded} />
             <div className="flex-1 mt-6 flex flex-col items-center justify-center text-cyber-dim/40 border-2 border-dashed border-cyber-border/30 rounded-xl bg-cyber-black/20 p-8 min-h-[400px]">
               <Activity size={80} strokeWidth={0.5} className="text-cyber-border" />
               <p className="mt-6 font-mono text-sm tracking-[0.3em] uppercase">No Images Loaded</p>
            </div>
          </div>
        ) : (
          <div className="flex-1 flex flex-col bg-cyber-dark/80 border border-cyber-border rounded-xl overflow-hidden shadow-inner relative">
            {/* Header / Toolbar for Preview */}
            <div className="bg-cyber-black/40 border-b border-cyber-border/50 px-4 py-2 flex items-center justify-between backdrop-blur-md z-20">
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => setIsABMode(!isABMode)}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded text-xs font-mono uppercase tracking-wider transition-all border ${
                    isABMode 
                    ? 'bg-cyber-primary/20 border-cyber-primary text-cyber-primary shadow-neon' 
                    : 'bg-cyber-panel/50 border-cyber-border text-cyber-dim hover:text-cyber-text'
                  }`}
                >
                  <Split size={14} />
                  {isABMode ? 'AB Mode On' : 'AB Mode Off'}
                </button>

                <div className="h-4 w-px bg-cyber-border/50"></div>

                <div className="flex items-center gap-2">
                  <label className="cursor-pointer bg-cyber-panel/50 border border-cyber-border px-3 py-1.5 rounded text-xs font-mono text-cyber-dim hover:text-cyber-text transition-all flex items-center gap-2 hover:border-cyber-primary/50">
                    <ImageIcon size={14} />
                    {referenceImage ? 'Change Ref' : 'Upload Ref'}
                    <input type="file" className="hidden" accept="image/*" onChange={handleReferenceInputChange} />
                  </label>

                  {referenceImage && (
                    <button 
                      onClick={clearReference}
                      className="text-red-400 hover:text-red-300 p-1.5"
                      title="Clear Reference"
                    >
                      <XCircle size={14} />
                    </button>
                  )}
                </div>
              </div>

              <div className="text-[10px] font-mono text-cyber-dim uppercase hidden sm:block">
                {isABMode ? (referenceImage ? 'A: Reference | B: Adjusted' : 'A: Original | B: Adjusted') : 'Visualizing Results'}
              </div>
            </div>

            {/* Main Preview Area */}
            <div 
              ref={previewContainerRef}
              className="flex-1 relative overflow-hidden flex items-center justify-center bg-[radial-gradient(#334155_1px,transparent_1px)] bg-[size:20px_20px] min-h-[300px] lg:min-h-[400px]"
            >
                {activeFileItem ? (
                    <div className="relative w-full h-full p-4 flex flex-col items-center justify-center">
                        <div className="relative shadow-2xl border border-cyber-border/50 max-h-full max-w-full group/preview overflow-hidden">

                            {/* Comparison Side B (Adjusted) - Always background or clipped */}
                            <img 
                                src={previewBlobUrl || activeFileItem.previewUrl} 
                                className="max-w-full block select-none pointer-events-none"
                                style={{ maxHeight: 'min(60vh, 700px)', objectFit: 'contain' }}
                                alt="Adjusted Preview" 
                            />

                            {/* Comparison Side A (Original or Reference) */}
                            {isABMode && (
                              <>
                                <div 
                                  className="absolute top-0 left-0 h-full overflow-hidden border-r border-cyber-primary/50 z-10"
                                  style={{ width: `${splitPosition}%` }}
                                >
                                  <img 
                                      src={referenceImage?.previewUrl || activeFileItem.previewUrl} 
                                      className="max-w-none block select-none pointer-events-none"
                                      style={{ 
                                        height: '100%', 
                                        width: 'auto',
                                        // This ensures the image doesn't stretch and stays aligned with the bottom image
                                        // We use the same container relative sizing
                                        position: 'absolute',
                                        top: 0,
                                        left: 0,
                                        minHeight: '100%',
                                        minWidth: '100%',
                                        objectFit: 'contain',
                                        objectPosition: 'center'
                                      }}
                                      alt="Comparison Preview" 
                                  />
                                </div>

                                {/* Draggable Divider Handle */}
                                <div 
                                  className="absolute top-0 bottom-0 z-20 w-1 bg-cyber-primary shadow-neon cursor-col-resize flex items-center justify-center"
                                  style={{ left: `calc(${splitPosition}% - 0.5px)` }}
                                  onMouseDown={(e) => { e.preventDefault(); setIsResizingSplit(true); }}
                                >
                                   <div className="w-6 h-6 bg-cyber-primary text-cyber-black rounded-full flex items-center justify-center shadow-lg border-2 border-white/20">
                                      <Split size={12} className="rotate-90" />
                                   </div>
                                </div>

                                <div className="absolute top-2 left-2 z-30 bg-cyber-black/80 text-cyber-accent text-[9px] font-mono px-2 py-0.5 rounded border border-cyber-accent/30 backdrop-blur-sm pointer-events-none shadow-lg">
                                  SIDE A: {referenceImage ? 'REF' : 'ORIG'}
                                </div>
                                <div className="absolute top-2 right-2 z-30 bg-cyber-black/80 text-cyber-primary text-[9px] font-mono px-2 py-0.5 rounded border border-cyber-primary/30 backdrop-blur-sm pointer-events-none shadow-lg">
                                  SIDE B: ADJUSTED
                                </div>
                              </>
                            )}

                            {!isABMode && (
                              <div className="absolute top-2 right-2 bg-cyber-black/80 text-cyber-primary text-[10px] font-mono px-2 py-1 rounded border border-cyber-primary/30 backdrop-blur-sm pointer-events-none shadow-lg">
                                PREVIEW
                              </div>
                            )}
                        </div>

                        <div className="mt-4 bg-cyber-panel/80 backdrop-blur-md border border-cyber-border/50 px-4 py-1.5 rounded-full flex items-center gap-4 text-xs font-mono shadow-lg">
                             <div className="flex items-center gap-2 text-cyber-text max-w-[150px] sm:max-w-[250px]">
                                <ImageIcon size={12} className="text-cyber-dim" />
                                <span className="truncate" title={activeFileItem.file.name}>{activeFileItem.file.name}</span>
                             </div>
                             <div className="w-px h-3 bg-cyber-dim/30"></div>
                             <div className="text-cyber-dim">
                                {activeFileItem.width} <span className="text-cyber-dim/50">x</span> {activeFileItem.height}
                             </div>
                        </div>
                    </div>
                ) : (
                    <div className="text-cyber-dim font-mono text-sm">Select an image to preview</div>
                )}
            </div>

            {/* File Strip */}
            <div className="h-24 bg-cyber-black/90 border-t border-cyber-border/50 p-2 flex gap-3 overflow-x-auto custom-scrollbar backdrop-blur-md flex-shrink-0 z-10 items-center">
                {files.map(file => (
                    <div 
                        key={file.id} 
                        onClick={() => setActivePreviewId(file.id)}
                        className={`
                            relative w-16 h-16 flex-shrink-0 cursor-pointer border rounded-md overflow-hidden transition-all group/item
                            ${activePreviewId === file.id ? 'border-cyber-primary ring-1 ring-cyber-primary shadow-[0_0_10px_rgba(6,182,212,0.3)] opacity-100' : 'border-cyber-border opacity-50 hover:opacity-90'}
                        `}
                    >
                        <img src={file.previewUrl} className="w-full h-full object-cover" alt="" />
                        {file.status === 'COMPLETED' && <div className="absolute inset-0 bg-emerald-500/20 flex items-center justify-center"><div className="w-2 h-2 rounded-full bg-emerald-400 shadow-neon"></div></div>}
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleRemoveFile(file.id); }}
                            className="absolute top-1 right-1 bg-black/70 text-white p-1 rounded-sm opacity-0 group-hover/item:opacity-100 hover:bg-red-500 hover:text-white transition-all backdrop-blur-sm"
                        >
                            <Trash2 size={10} />
                        </button>
                    </div>
                ))}

                <div className="w-16 h-16 flex-shrink-0">
                     <Dropzone onFilesAdded={handleFilesAdded} compact={true} />
                </div>
            </div>
          </div>
        )}
      </div>

      {/* Right Column: Curve Editor */}
      <div className="lg:col-span-4 space-y-6 order-1 lg:order-2 flex flex-col h-fit sticky top-8">
        <div className="bg-cyber-panel/40 backdrop-blur-md border border-cyber-border p-6 shadow-2xl rounded-lg relative overflow-hidden">
            <div className="absolute top-0 right-0 w-20 h-20 bg-cyber-primary/5 rounded-full blur-2xl -mr-10 -mt-10 pointer-events-none"></div>

            <div className="flex items-center justify-between mb-6 relative z-10">
                <h2 className="text-lg font-bold text-cyber-text flex items-center gap-3 font-mono uppercase tracking-wide">
                    <Activity size={18} className="text-cyber-primary" />
                    Curve Map
                </h2>
                <button 
                    onClick={resetCurves}
                    className="text-[10px] flex items-center gap-1 text-cyber-dim hover:text-cyber-primary transition-colors uppercase tracking-wider bg-cyber-black/50 px-2 py-1 rounded border border-cyber-border/50"
                >
                    <RotateCcw size={10} /> Reset
                </button>
            </div>

            <div className="aspect-square relative bg-cyber-black border border-cyber-border rounded-lg shadow-inner select-none cursor-crosshair group overflow-hidden" ref={graphRef} onClick={handleGraphClick}>
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-20">
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div></div>
                </div>

                <div className="absolute inset-0 border-t border-l border-transparent">
                     <svg className="w-full h-full pointer-events-none opacity-10" viewBox="0 0 100 100" preserveAspectRatio="none">
                         <line x1="0" y1="100" x2="100" y2="0" stroke="currentColor" strokeWidth="0.5" className="text-cyber-dim" />
                     </svg>
                </div>

                <svg className="absolute inset-0 w-full h-full pointer-events-none z-10 overflow-visible">
                    <path 
                        d={generateSvgPath()} 
                        fill="none" 
                        stroke="#06b6d4" 
                        strokeWidth="4" 
                        strokeOpacity="0.2"
                        vectorEffect="non-scaling-stroke"
                        className="blur-sm"
                    />
                    <path 
                        d={generateSvgPath()} 
                        fill="none" 
                        stroke="#06b6d4" 
                        strokeWidth="2" 
                        vectorEffect="non-scaling-stroke"
                        className="drop-shadow-[0_0_2px_rgba(255,255,255,0.5)]"
                    />
                    <path 
                        d={`${generateSvgPath()} L 100% 100% L 0 100% Z`} 
                        fill="url(#curveGradient)" 
                        opacity="0.15"
                    />
                    <defs>
                        <linearGradient id="curveGradient" x1="0" x2="0" y1="0" y2="1">
                            <stop offset="0%" stopColor="#06b6d4" />
                            <stop offset="100%" stopColor="transparent" />
                        </linearGradient>
                    </defs>
                </svg>

                {points.map((p, index) => (
                    <div
                        key={p.id}
                        className={`absolute w-3 h-3 -ml-1.5 -mt-1.5 rounded-full border-2 cursor-grab active:cursor-grabbing transition-transform z-20 ${
                            draggingPointId === p.id 
                            ? 'bg-cyber-text border-cyber-primary shadow-[0_0_15px_rgba(6,182,212,0.8)] scale-150' 
                            : 'bg-cyber-black border-cyber-primary hover:scale-125'
                        }`}
                        style={{
                            left: `${(p.x / 255) * 100}%`,
                            top: `${100 - (p.y / 255) * 100}%`
                        }}
                        onMouseDown={(e) => {
                            e.stopPropagation();
                            setDraggingPointId(p.id);
                        }}
                        onDoubleClick={(e) => {
                            e.stopPropagation();
                            if (index !== 0 && index !== points.length - 1) {
                                removePoint(p.id);
                            }
                        }}
                    ></div>
                ))}
            </div>

            <div className="mt-4 text-center">
                <p className="text-[10px] text-cyber-dim uppercase tracking-widest font-mono">
                    Double-click point to delete • Drag to adjust
                </p>
            </div>
        </div>

        <div className="bg-cyber-panel/20 border border-cyber-border p-4 rounded-lg space-y-3">
             <div className="flex justify-between text-xs font-mono text-cyber-dim uppercase">
                 <span>Batch Ready</span>
                 <span className={files.length > 0 ? 'text-cyber-text' : ''}>{files.length} Images</span>
             </div>

             <button
                onClick={applyBatch}
                disabled={isProcessing || files.length === 0}
                className="w-full py-3 bg-cyber-primary/10 border border-cyber-primary text-cyber-primary font-bold text-xs uppercase tracking-widest hover:bg-cyber-primary/20 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
             >
                {isProcessing ? <RefreshCw size={16} className="animate-spin" /> : <RefreshCw size={16} />}
                APPLY CURVES
             </button>

             {completedCount > 0 && !isProcessing && (
                <button
                    onClick={downloadZip}
                    className="w-full py-3 bg-cyber-accent/10 border border-cyber-accent text-cyber-accent font-bold text-xs uppercase tracking-widest hover:bg-cyber-accent/20 transition-all flex items-center justify-center gap-2"
                >
                    <Download size={16} />
                    DOWNLOAD ZIP ({completedCount})
                </button>
             )}
        </div>
      </div>
    </main>
  );
};

export default CurvesAdjustmentView;

import { useState, useCallback, useMemo, useEffect } from 'react';
import { ImageFile, ConversionStatus, CurvePoint } from '../types';
import { applyCurvesToImage, getImageDimensions } from '../utils/imageHelper';
import { generateCurveLUT } from '../utils/curveAlgorithms';
import { generateId, getZip } from '../utils/common';

const DEFAULT_POINTS: CurvePoint[] = [
  { id: 'start', x: 0, y: 0 },
  { id: 'end', x: 255, y: 255 }
];

export interface ReferenceImage {
  id: string;
  file: File;
  previewUrl: string;
}

export const useImageCurves = () => {
  const [files, setFiles] = useState<ImageFile[]>([]);
  const [points, setPoints] = useState<CurvePoint[]>(DEFAULT_POINTS);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activePreviewId, setActivePreviewId] = useState<string | null>(null);

  // AB Comparison State
  const [referenceImage, setReferenceImage] = useState<ReferenceImage | null>(null);
  const [isABMode, setIsABMode] = useState(true); // Default to on for immediate feedback
  const [splitPosition, setSplitPosition] = useState(50); // 0 to 100

  // Computed LUT based on points
  const lut = useMemo(() => generateCurveLUT(points), [points]);

  const handleFilesAdded = useCallback(async (newFiles: File[]) => {
    const processedFilesPromises = newFiles.map(async (file) => {
      const dimensions = await getImageDimensions(file);
      return {
        id: generateId(),
        file,
        previewUrl: URL.createObjectURL(file), 
        status: ConversionStatus.IDLE,
        originalSize: file.size,
        width: dimensions.width,
        height: dimensions.height,
      } as ImageFile;
    });

    const newImageFiles = await Promise.all(processedFilesPromises);
    setFiles(prev => {
        const updated = [...prev, ...newImageFiles];
        if (!activePreviewId && updated.length > 0) {
            setActivePreviewId(updated[0].id);
        }
        return updated;
    });
  }, [activePreviewId]);

  const handleReferenceAdded = useCallback(async (file: File) => {
    if (referenceImage) {
      URL.revokeObjectURL(referenceImage.previewUrl);
    }
    const previewUrl = URL.createObjectURL(file);
    setReferenceImage({
      id: generateId(),
      file,
      previewUrl
    });
    setIsABMode(true);
  }, [referenceImage]);

  const clearReference = useCallback(() => {
    if (referenceImage) {
      URL.revokeObjectURL(referenceImage.previewUrl);
    }
    setReferenceImage(null);
  }, [referenceImage]);

  const handleRemoveFile = useCallback((id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) {
        URL.revokeObjectURL(target.previewUrl);
      }
      const remaining = prev.filter(f => f.id !== id);
      if (activePreviewId === id) {
          setActivePreviewId(remaining.length > 0 ? remaining[0].id : null);
      }
      return remaining;
    });
  }, [activePreviewId]);

  const addPoint = (x: number, y: number) => {
    if (points.some(p => Math.abs(p.x - x) < 5)) return;
    const newPoint: CurvePoint = { id: generateId(), x, y };
    setPoints(prev => [...prev, newPoint].sort((a, b) => a.x - b.x));
  };

  const updatePoint = (id: string, x: number, y: number) => {
    setPoints(prev => prev.map(p => {
        if (p.id !== id) return p;
        return { ...p, x: Math.max(0, Math.min(255, x)), y: Math.max(0, Math.min(255, y)) };
    }).sort((a, b) => a.x - b.x));
  };

  const removePoint = (id: string) => {
      if (points.length <= 2) return; 
      setPoints(prev => prev.filter(p => p.id !== id));
  };

  const resetCurves = () => setPoints([
      { id: 'start', x: 0, y: 0 },
      { id: 'end', x: 255, y: 255 }
  ]);

  const applyBatch = async () => {
    setIsProcessing(true);
    for (const file of files) {
        if (file.status === ConversionStatus.COMPLETED) continue;
        setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: ConversionStatus.PROCESSING } : f));
        try {
            const blob = await applyCurvesToImage(file.file, lut);
            setFiles(prev => prev.map(f => 
                f.id === file.id ? { 
                    ...f, 
                    status: ConversionStatus.COMPLETED, 
                    convertedBlob: blob,
                    convertedSize: blob.size 
                } : f
            ));
        } catch (e) {
            console.error(e);
            setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: ConversionStatus.ERROR } : f));
        }
    }
    setIsProcessing(false);
  };

  const downloadZip = async () => {
      try {
        const zip = getZip();
        const completedFiles = files.filter(f => f.status === ConversionStatus.COMPLETED && f.convertedBlob);
        if (completedFiles.length === 0) return;
        completedFiles.forEach(f => {
          const fileName = f.file.name.replace(/\.(png|jpe?g)$/i, '') + '_curve.jpg';
          if (f.convertedBlob) {
            zip.file(fileName, f.convertedBlob);
          }
        });
        const content = await zip.generateAsync({ type: "blob" });
        const url = URL.createObjectURL(content);
        const a = document.createElement("a");
        a.href = url;
        a.download = `BatchBox_Curves_${new Date().toISOString().slice(0,10)}.zip`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      } catch (error) {
        console.error("ZIP generation failed", error);
        alert("Failed to generate ZIP.");
      }
  };

  return {
      files,
      points,
      isProcessing,
      activePreviewId,
      setActivePreviewId,
      handleFilesAdded,
      handleRemoveFile,
      addPoint,
      updatePoint,
      removePoint,
      resetCurves,
      applyBatch,
      downloadZip,
      lut,
      // AB Mode exports
      referenceImage,
      handleReferenceAdded,
      clearReference,
      isABMode,
      setIsABMode,
      splitPosition,
      setSplitPosition
  };
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { useImageCurves } from '../../hooks/useImageCurves';
import { Activity, Download, RefreshCw, Trash2, RotateCcw, Image as ImageIcon, Plus, XCircle, Split, MousePointer2 } from 'lucide-react';
import Dropzone from '../Dropzone';
import { applyCurvesToImage } from '../../utils/imageHelper';
import { ConversionStatus } from '../../types';

interface CurvesAdjustmentViewProps {
  controller: ReturnType<typeof useImageCurves>;
}

const CurvesAdjustmentView: React.FC<CurvesAdjustmentViewProps> = ({ controller }) => {
  const {
    files,
    points,
    isProcessing,
    activePreviewId,
    setActivePreviewId,
    handleFilesAdded,
    handleRemoveFile,
    addPoint,
    updatePoint,
    removePoint,
    resetCurves,
    applyBatch,
    downloadZip,
    lut,
    // AB Mode
    referenceImage,
    handleReferenceAdded,
    clearReference,
    isABMode,
    setIsABMode,
    splitPosition,
    setSplitPosition
  } = controller;

  const graphRef = useRef<HTMLDivElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const [draggingPointId, setDraggingPointId] = useState<string | null>(null);
  const [previewBlobUrl, setPreviewBlobUrl] = useState<string | null>(null);
  const [isDragOver, setIsDragOver] = useState(false);
  const [isResizingSplit, setIsResizingSplit] = useState(false);

  const completedCount = files.filter(f => f.status === ConversionStatus.COMPLETED).length;

  // Generate preview whenever LUT or active file changes
  useEffect(() => {
    const activeFile = files.find(f => f.id === activePreviewId);
    if (!activeFile) {
        setPreviewBlobUrl(null);
        return;
    }

    const timer = setTimeout(async () => {
        try {
            const blob = await applyCurvesToImage(activeFile.file, lut);
            const url = URL.createObjectURL(blob);
            setPreviewBlobUrl(prev => {
                if (prev) URL.revokeObjectURL(prev);
                return url;
            });
        } catch (e) {
            console.error("Preview generation failed", e);
        }
    }, 40);

    return () => clearTimeout(timer);
  }, [activePreviewId, lut, files]); 

  const handleGraphClick = (e: React.MouseEvent) => {
    if (draggingPointId) return;
    if (!graphRef.current) return;
    const rect = graphRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));
    addPoint(x, y);
  };

  const handleMouseMoveGlobal = useCallback((e: MouseEvent) => {
    if (draggingPointId && graphRef.current) {
      const rect = graphRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));
      updatePoint(draggingPointId, x, y);
    }

    if (isResizingSplit && previewContainerRef.current) {
      const rect = previewContainerRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(100, ((e.clientX - rect.left) / rect.width) * 100));
      setSplitPosition(x);
    }
  }, [draggingPointId, isResizingSplit, updatePoint, setSplitPosition]);

  const handleMouseUpGlobal = useCallback(() => {
    setDraggingPointId(null);
    setIsResizingSplit(false);
  }, []);

  useEffect(() => {
    if (draggingPointId || isResizingSplit) {
        window.addEventListener('mousemove', handleMouseMoveGlobal);
        window.addEventListener('mouseup', handleMouseUpGlobal);
    }
    return () => {
        window.removeEventListener('mousemove', handleMouseMoveGlobal);
        window.removeEventListener('mouseup', handleMouseUpGlobal);
    };
  }, [draggingPointId, isResizingSplit, handleMouseMoveGlobal, handleMouseUpGlobal]);

  const generateSvgPath = () => {
     let d = `M 0 ${255 - lut[0]}`;
     for(let i = 1; i < 256; i++) {
