                    <ImageIcon size={14} />
                    {referenceImage ? 'Change Ref' : 'Upload Ref'}
                    <input type="file" className="hidden" accept="image/*" onChange={handleReferenceInputChange} />
                  </label>

                  {referenceImage && (
