              <div className="text-[10px] font-mono text-cyber-dim uppercase hidden sm:block">
                {isABMode ? (referenceImage ? 'REF vs ADJ' : 'ORIG vs ADJ') : 'Visualizing Results'}
              </div>
            </div>

            {/* Main Preview Area */}
