                {points.map((p, index) => (
                    <div
                        key={p.id}
                        className={`absolute w-2.5 h-2.5 -ml-1.25 -mt-1.25 border rounded-full cursor-grab active:cursor-grabbing z-20 transition-transform hover:scale-125 ${
                            draggingPointId === p.id ? 'bg-white border-cyber-primary shadow-[0_0_10px_white]' : 'bg-cyber-black border-cyber-primary hover:bg-cyber-primary shadow-lg'
                        }`}
                        style={{ left: `${(p.x / 255) * 100}%`, top: `${100 - (p.y / 255) * 100}%` }}
                        onMouseDown={(e) => { e.stopPropagation(); setDraggingPointId(p.id); }}
                        onDoubleClick={(e) => { e.stopPropagation(); if (index !== 0 && index !== points.length - 1) removePoint(p.id); }}
                    ></div>
                ))}
            </div>
            <div className="mt-2 text-[8px] text-cyber-dim/50 font-mono uppercase text-center tracking-tighter">
