        </div>

        {/* Action Panel */}
        <div className="bg-cyber-black/40 border border-cyber-border p-4 flex flex-col gap-3 shrink-0 rounded-sm">
             <div className="flex justify-between text-[9px] font-mono text-cyber-dim uppercase tracking-widest border-b border-cyber-border/30 pb-2">
                 <span>Processor Queue</span>
                 <span className="text-cyber-text font-bold">{files.length} ITEMS</span>
             </div>

             <button
                onClick={applyBatch}
                disabled={isProcessing || files.length === 0}
