{
  "name": "BatchBox",
  "description": "A client-side batch image converter that transforms PNG, JPG, and WebP files to standardized JPG format and bundles them into a ZIP archive, ensuring privacy with zero server uploads.",
  "requestFramePermissions": []
}

import React, { useCallback, useState } from 'react';
import { UploadCloud, AlertCircle, Plus, FolderArchive, Loader2 } from 'lucide-react';

interface DropzoneProps {
  onFilesAdded: (files: File[]) => void;
  disabled?: boolean;
  compact?: boolean;
  mode?: 'image' | 'folder'; // New prop to switch modes
}

const Dropzone: React.FC<DropzoneProps> = ({ 
  onFilesAdded, 
  disabled, 
  compact = false, 
  mode = 'image' 
}) => {
  const [isDragActive, setIsDragActive] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!disabled) setIsDragActive(true);
  }, [disabled]);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragActive(false);
  }, []);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  }, []);

  // Helper: Read all entries from a directory reader (handles pagination)
  const readAllEntries = async (dirReader: any): Promise<any[]> => {
    const entries: any[] = [];
    let readResults = await new Promise<any[]>((resolve, reject) => 
      dirReader.readEntries(resolve, reject)
    );

    while (readResults.length > 0) {
      entries.push(...readResults);
      readResults = await new Promise<any[]>((resolve, reject) => 
        dirReader.readEntries(resolve, reject)
      );
    }
    return entries;
  };

  // Helper: Recursively traverse FileSystemEntry
  const traverseFileTree = async (entry: any, path: string = ''): Promise<File[]> => {
    if (entry.isFile) {
      return new Promise<File[]>((resolve) => {
        entry.file((file: File) => {
          // Manually patch webkitRelativePath for correct grouping
          const fullPath = path + entry.name;
          Object.defineProperty(file, 'webkitRelativePath', {
            value: fullPath,
            writable: true
          });
          resolve([file]);
        }, () => resolve([])); // Resolve empty on error
      });
    } else if (entry.isDirectory) {
      const dirReader = entry.createReader();
      const entries = await readAllEntries(dirReader);
      const promises = entries.map(child => traverseFileTree(child, path + entry.name + '/'));
      const results = await Promise.all(promises);
      return results.flat();
    }
    return [];
  };

  const validateAndAddFiles = (fileList: FileList | null) => {
    if (!fileList) return;

    const files = Array.from(fileList);

    if (mode === 'image') {
      const validFiles: File[] = [];
      let hasInvalid = false;

      files.forEach(file => {
        const type = file.type;
        if (type === 'image/png' || type === 'image/jpeg' || type === 'image/webp') {
          validFiles.push(file);
        } else {
          hasInvalid = true;
        }
      });

      if (hasInvalid) {
        setError('Only PNG, JPG, and WebP files are supported.');
        setTimeout(() => setError(null), 3000);
      }

      if (validFiles.length > 0) {
        onFilesAdded(validFiles);
      }
    } else {
      onFilesAdded(files);
    }
  };

  const handleDrop = useCallback(async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragActive(false);
    if (disabled || isScanning) return;

    if (mode === 'folder') {
       const items = e.dataTransfer.items;
       if (items && items.length > 0) {
          const entries = Array.from(items)
             .map(item => typeof (item as any).webkitGetAsEntry === 'function' ? (item as any).webkitGetAsEntry() : null)
             .filter(Boolean);

          if (entries.length > 0) {
             setIsScanning(true);
             try {
                const scanPromises = entries.map(entry => traverseFileTree(entry));
                const results = await Promise.all(scanPromises);
                const allFiles = results.flat();

                if (allFiles.length > 0) {
                   onFilesAdded(allFiles);
                } else {
                   setError("No files found in dropped folders.");
                   setTimeout(() => setError(null), 3000);
                }
             } catch (err) {
                console.error("Scanning failed", err);
                setError("Failed to scan directory structure.");
                setTimeout(() => setError(null), 3000);
             } finally {
                setIsScanning(false);
             }
             return;
          }
       }
    }

    validateAndAddFiles(e.dataTransfer.files);
  }, [disabled, onFilesAdded, mode, isScanning]);

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (disabled) return;
    validateAndAddFiles(e.target.files);
    e.target.value = '';
  };

  const title = mode === 'image' 
    ? (compact ? 'ADD' : 'DROP PNG / JPG / WEBP') 
    : (compact ? 'ADD' : 'DROP FOLDERS HERE');

  const subTitle = mode === 'image'
    ? 'Or Click to Browse'
    : 'Drag multiple folders';

  return (
    <div className={`w-full h-full ${compact ? 'flex items-center justify-center' : ''}`}>
      <div
        onDragEnter={handleDragEnter}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        className={`
          relative border-2 border-dashed rounded-xl transition-all duration-300 ease-in-out text-center cursor-pointer group w-full h-full flex flex-col items-center justify-center
          ${compact ? 'p-1' : 'p-10'}
          ${isDragActive 
            ? 'border-cyber-primary bg-cyber-primary/10 shadow-neon scale-[1.01]' 
            : 'border-cyber-border hover:border-cyber-primary/50 hover:bg-cyber-dark hover:shadow-lg bg-cyber-black/50'
          }
          ${(disabled || isScanning) ? 'opacity-50 cursor-not-allowed pointer-events-none grayscale' : ''}
        `}
      >
        <input
          type="file"
          multiple
          {...(mode === 'folder' ? { webkitdirectory: "", directory: "" } as any : { accept: "image/png, image/jpeg, image/webp" })}
          onChange={handleFileInput}
          disabled={disabled || isScanning}
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer disabled:cursor-not-allowed"
        />

        <div className={`flex flex-col items-center justify-center pointer-events-none ${compact ? 'gap-1' : 'space-y-4'}`}>
          <div className={`
            rounded-full transition-colors duration-300 flex items-center justify-center
            ${compact ? 'p-1.5' : 'p-4'}
            ${isDragActive ? 'bg-cyber-primary text-cyber-black' : 'bg-cyber-panel text-cyber-primary group-hover:text-cyan-300'}
          `}>
            {isScanning ? (
               <Loader2 size={compact ? 16 : 48} className="animate-spin" strokeWidth={1.5} />
            ) : compact ? (
              <Plus size={16} strokeWidth={2.5} />
            ) : (
              mode === 'image' ? <UploadCloud size={48} strokeWidth={1.5} /> : <FolderArchive size={48} strokeWidth={1.5} />
            )}
          </div>
          <div>
            <h3 className={`font-bold text-cyber-text tracking-wide group-hover:text-cyber-primary transition-colors ${compact ? 'text-[10px]' : 'text-xl'}`}>
              {isScanning ? 'SCAN' : title}
            </h3>
            {!compact && !isScanning && (
              <p className="text-cyber-dim mt-2 text-sm font-mono uppercase tracking-wider">
                {subTitle}
              </p>
            )}
          </div>
        </div>

        {error && (
          <div className="absolute bottom-4 left-1/2 transform -translate-x-1/2 flex items-center gap-2 text-red-400 bg-red-900/80 border border-red-700/50 px-4 py-2 rounded-full text-sm animate-bounce shadow-lg z-20 w-max max-w-[90%]">
            <AlertCircle size={16} />
            <span>{error}</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dropzone;

import { useState, useCallback, useMemo } from 'react';
import { ImageFile, ConversionStatus, ConversionConfig } from '../types';
import { convertImageToJpg, getImageDimensions } from '../utils/imageHelper';
import { generateId, getZip } from '../utils/common';

export const useImageConverter = () => {
  const [files, setFiles] = useState<ImageFile[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [config, setConfig] = useState<ConversionConfig>({
    quality: 0.9,
    fillColor: '#FFFFFF',
    scale: 1,
  });
  const [processedCount, setProcessedCount] = useState(0);

  const handleFilesAdded = useCallback(async (newFiles: File[]) => {
    const processedFilesPromises = newFiles.map(async (file) => {
      const dimensions = await getImageDimensions(file);
      return {
        id: generateId(),
        file,
        previewUrl: URL.createObjectURL(file),
        status: ConversionStatus.IDLE,
        originalSize: file.size,
        width: dimensions.width,
        height: dimensions.height,
      } as ImageFile;
    });

    const newImageFiles = await Promise.all(processedFilesPromises);
    setFiles(prev => [...prev, ...newImageFiles]);
  }, []);

  const handleRemoveFile = useCallback((id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) {
        URL.revokeObjectURL(target.previewUrl);
      }
      return prev.filter(f => f.id !== id);
    });
  }, []);

  const handleClearAll = useCallback(() => {
    files.forEach(f => URL.revokeObjectURL(f.previewUrl));
    setFiles([]);
    setProcessedCount(0);
  }, [files]);

  const startConversion = async () => {
    setIsProcessing(true);
    setProcessedCount(0);

    const filesToProcess = files.filter(f => f.status !== ConversionStatus.COMPLETED);

    for (let i = 0; i < filesToProcess.length; i++) {
      const currentId = filesToProcess[i].id;
      setFiles(prev => prev.map(f => f.id === currentId ? { ...f, status: ConversionStatus.PROCESSING } : f));

      try {
        const jpgBlob = await convertImageToJpg(filesToProcess[i].file, config);
        setFiles(prev => prev.map(f => 
          f.id === currentId ? { 
            ...f, 
            status: ConversionStatus.COMPLETED, 
            convertedBlob: jpgBlob,
            convertedSize: jpgBlob.size 
          } : f
        ));
        setProcessedCount(prev => prev + 1);
      } catch (error) {
        console.error("Conversion failed", error);
        setFiles(prev => prev.map(f => 
          f.id === currentId ? { ...f, status: ConversionStatus.ERROR, errorMessage: 'Failed' } : f
        ));
      }
    }
    setIsProcessing(false);
  };

  const downloadZip = async () => {
    try {
      const zip = getZip();
      const completedFiles = files.filter(f => f.status === ConversionStatus.COMPLETED && f.convertedBlob);
      if (completedFiles.length === 0) return;

      completedFiles.forEach(f => {
        const fileName = f.file.name.replace(/\.(png|jpe?g|webp)$/i, '') + '.jpg';
        if (f.convertedBlob) {
          zip.file(fileName, f.convertedBlob);
        }
      });

      const content = await zip.generateAsync({ type: "blob" });
      const url = URL.createObjectURL(content);
      const a = document.createElement("a");
      a.href = url;
      a.download = `BatchBox_Images_${new Date().toISOString().slice(0,10)}.zip`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error("ZIP generation failed", error);
      alert("Failed to generate ZIP.");
    }
  };

  const stats = useMemo(() => {
    const completed = files.filter(f => f.status === ConversionStatus.COMPLETED).length;
    const total = files.length;
    const totalConvertedSize = files.reduce((acc, curr) => acc + (curr.convertedSize || 0), 0);
    return { completed, total, totalConvertedSize };
  }, [files]);

  return {
    files,
    isProcessing,
    config,
    setConfig,
    processedCount,
    stats,
    handleFilesAdded,
    handleRemoveFile,
    handleClearAll,
    startConversion,
    downloadZip
  };
};

import { useState, useCallback, useMemo, useEffect } from 'react';
import { ImageFile, ConversionStatus, CurvePoint, CurvePreset } from '../types';
import { applyCurvesToImage, getImageDimensions } from '../utils/imageHelper';
import { generateCurveLUT } from '../utils/curveAlgorithms';
import { generateId, getZip } from '../utils/common';

const STORAGE_KEY = 'batchbox_curve_points';
const COLOR_STORAGE_KEY = 'batchbox_color_tuning';
const PRESETS_STORAGE_KEY = 'batchbox_curve_presets';

const DEFAULT_POINTS: CurvePoint[] = [
  { id: 'start', x: 0, y: 0 },
  { id: 'end', x: 255, y: 255 }
];

export interface ReferenceImage {
  id: string;
  file: File;
  previewUrl: string;
}

export const useImageCurves = () => {
  const [files, setFiles] = useState<ImageFile[]>([]);

  // Initialize points from local storage
  const [points, setPoints] = useState<CurvePoint[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length >= 2) return parsed;
      }
    } catch (e) {}
    return DEFAULT_POINTS;
  });

  // Color Tuning State (-100 to 100)
  const [colorTuning, setColorTuning] = useState<{ temperature: number, tint: number }>(() => {
    try {
      const saved = localStorage.getItem(COLOR_STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {}
    return { temperature: 0, tint: 0 };
  });

  // Presets State
  const [presets, setPresets] = useState<CurvePreset[]>(() => {
    try {
      const saved = localStorage.getItem(PRESETS_STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {}
    return [];
  });

  const [isProcessing, setIsProcessing] = useState(false);
  const [activePreviewId, setActivePreviewId] = useState<string | null>(null);
  const [referenceImage, setReferenceImage] = useState<ReferenceImage | null>(null);
  const [isABMode, setIsABMode] = useState(true); 
  const [splitPosition, setSplitPosition] = useState(50); 

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(points));
  }, [points]);

  useEffect(() => {
    localStorage.setItem(COLOR_STORAGE_KEY, JSON.stringify(colorTuning));
  }, [colorTuning]);

  useEffect(() => {
    localStorage.setItem(PRESETS_STORAGE_KEY, JSON.stringify(presets));
  }, [presets]);

  const lut = useMemo(() => generateCurveLUT(points), [points]);

  const handleFilesAdded = useCallback(async (newFiles: File[]) => {
    const processedFilesPromises = newFiles.map(async (file) => {
      const dimensions = await getImageDimensions(file);
      return {
        id: generateId(),
        file,
        previewUrl: URL.createObjectURL(file), 
        status: ConversionStatus.IDLE,
        originalSize: file.size,
        width: dimensions.width,
        height: dimensions.height,
      } as ImageFile;
    });

    const newImageFiles = await Promise.all(processedFilesPromises);
    setFiles(prev => {
        const updated = [...prev, ...newImageFiles];
        if (!activePreviewId && updated.length > 0) setActivePreviewId(updated[0].id);
        return updated;
    });
  }, [activePreviewId]);

  const handleReferenceAdded = useCallback(async (file: File) => {
    if (referenceImage) URL.revokeObjectURL(referenceImage.previewUrl);
    const previewUrl = URL.createObjectURL(file);
    setReferenceImage({ id: generateId(), file, previewUrl });
    setIsABMode(true);
  }, [referenceImage]);

  const clearReference = useCallback(() => {
    if (referenceImage) URL.revokeObjectURL(referenceImage.previewUrl);
    setReferenceImage(null);
  }, [referenceImage]);

  const handleRemoveFile = useCallback((id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) URL.revokeObjectURL(target.previewUrl);
      const remaining = prev.filter(f => f.id !== id);
      if (activePreviewId === id) setActivePreviewId(remaining.length > 0 ? remaining[0].id : null);
      return remaining;
    });
  }, [activePreviewId]);

  const handleClearAll = useCallback(() => {
    files.forEach(f => URL.revokeObjectURL(f.previewUrl));
    setFiles([]);
    setActivePreviewId(null);
  }, [files]);

  const addPoint = (x: number, y: number) => {
    if (points.some(p => Math.abs(p.x - x) < 5)) return;
    const newPoint: CurvePoint = { id: generateId(), x, y };
    setPoints(prev => [...prev, newPoint].sort((a, b) => a.x - b.x));
  };

  const updatePoint = (id: string, x: number, y: number) => {
    setPoints(prev => prev.map(p => {
        if (p.id !== id) return p;
        return { ...p, x: Math.max(0, Math.min(255, x)), y: Math.max(0, Math.min(255, y)) };
    }).sort((a, b) => a.x - b.x));
  };

  const removePoint = (id: string) => {
      if (points.length <= 2) return; 
      setPoints(prev => prev.filter(p => p.id !== id));
  };

  const resetCurves = () => setPoints(DEFAULT_POINTS);
  const resetColorTuning = () => setColorTuning({ temperature: 0, tint: 0 });

  // Preset Management
  const savePreset = (name: string) => {
    const newPreset: CurvePreset = {
      id: generateId(),
      name,
      points: [...points],
      colorTuning: { ...colorTuning },
      timestamp: Date.now()
    };
    setPresets(prev => [newPreset, ...prev]);
  };

  const loadPreset = (presetId: string) => {
    const preset = presets.find(p => p.id === presetId);
    if (preset) {
      setPoints(preset.points);
      setColorTuning(preset.colorTuning);
    }
  };

  const deletePreset = (presetId: string) => {
    setPresets(prev => prev.filter(p => p.id !== presetId));
  };

  const applyBatch = async () => {
    setIsProcessing(true);
    for (const file of files) {
        if (file.status === ConversionStatus.COMPLETED) continue;
        setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: ConversionStatus.PROCESSING } : f));
        try {
            const blob = await applyCurvesToImage(file.file, lut, 0.9, colorTuning);
            setFiles(prev => prev.map(f => 
                f.id === file.id ? { 
                    ...f, 
                    status: ConversionStatus.COMPLETED, 
                    convertedBlob: blob,
                    convertedSize: blob.size 
                } : f
            ));
        } catch (e) {
            console.error(e);
            setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: ConversionStatus.ERROR } : f));
        }
    }
    setIsProcessing(false);
  };

  const downloadZip = async () => {
      try {
        const zip = getZip();
        const completedFiles = files.filter(f => f.status === ConversionStatus.COMPLETED && f.convertedBlob);
        if (completedFiles.length === 0) return;
        completedFiles.forEach(f => {
          const fileName = f.file.name.replace(/\.(png|jpe?g|webp)$/i, '') + '_processed.jpg';
          if (f.convertedBlob) zip.file(fileName, f.convertedBlob);
        });
        const content = await zip.generateAsync({ type: "blob" });
        const url = URL.createObjectURL(content);
        const a = document.createElement("a");
        a.href = url;
        a.download = `BatchBox_Processed_${new Date().toISOString().slice(0,10)}.zip`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      } catch (error) {
        console.error("ZIP generation failed", error);
      }
  };

  return {
      files,
      points,
      colorTuning,
      setColorTuning,
      presets,
      savePreset,
      loadPreset,
      deletePreset,
      isProcessing,
      activePreviewId,
      setActivePreviewId,
      handleFilesAdded,
      handleRemoveFile,
      handleClearAll,
      addPoint,
      updatePoint,
      removePoint,
      resetCurves,
      resetColorTuning,
      applyBatch,
      downloadZip,
      lut,
      referenceImage,
      handleReferenceAdded,
      clearReference,
      isABMode,
      setIsABMode,
      splitPosition,
      setSplitPosition
  };
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { useImageCurves } from '../../hooks/useImageCurves';
import { Activity, Download, RefreshCw, Trash2, RotateCcw, Image as ImageIcon, XCircle, Split, MousePointer2, Thermometer, Palette, Save, Bookmark, Zap } from 'lucide-react';
